# =========================================================
# Utilities
# =========================================================
def clean_text(value) -> str:
    if pd.isna(value):
        return ""
    return (
        str(value)
        .replace("\n", "")
        .replace("\r", "")
        .replace("\t", "")
        .replace("　", "")
        .strip()
    )


def normalize_column_name(value) -> str:
    return clean_text(value).replace(" ", "")


def deduplicate_columns(columns: List[str]) -> List[str]:
    output: List[str] = []
    counter: Dict[str, int] = {}
    for col in columns:
        name = normalize_column_name(col) or "未命名欄位"
        counter[name] = counter.get(name, 0) + 1
        output.append(name if counter[name] == 1 else f"{name}_{counter[name]}")
    return output


def find_column(columns: List[str], candidates: List[str]) -> Optional[str]:
    mapping = {normalize_column_name(col): col for col in columns}
    for candidate in candidates:
        key = normalize_column_name(candidate)
        if key in mapping:
            return mapping[key]
    for col in columns:
        ncol = normalize_column_name(col)
        for candidate in candidates:
            ncandidate = normalize_column_name(candidate)
            if ncandidate and (ncandidate in ncol or ncol in ncandidate):
                return col
    return None


def find_best_sheet_and_header(excel_bytes: bytes, max_rows: int = 50) -> Tuple[str, int]:
    keywords = [
        "製令", "工單", "Category", "機型", "組立地點",
        "組裝地點", "客戶入庫日", "入庫日", "發料日", "數量"
    ]
    xls = pd.ExcelFile(io.BytesIO(excel_bytes))
    best_sheet = xls.sheet_names[0]
    best_row = 0
    best_score = -1

    for sheet in xls.sheet_names:
        try:
            preview = pd.read_excel(
                io.BytesIO(excel_bytes),
                sheet_name=sheet,
                header=None,
                nrows=max_rows,
                dtype=object,
            )
        except Exception:
            continue

        for idx, row in preview.iterrows():
            text = "|".join(normalize_column_name(v) for v in row.tolist())
            score = sum(normalize_column_name(k) in text for k in keywords)
            if score > best_score:
                best_score = score
                best_sheet = sheet
                best_row = int(idx)

    return best_sheet, best_row


def normalize_model(value) -> str:
    text = clean_text(value)
    key = text.lower().replace(" ", "")
    aliases = {
        "efem": "EFEM",
        "sort": "sort",
        "sorter": "sort",
        "sorting": "sort",
        "骨包": "骨包",
        "bws": "BWS",
        "bwbs": "BWS",
        "ntb": "NTB",
        "other": "other",
        "其他": "other",
    }
    return aliases.get(key, "other")


def parse_holidays(text: str) -> List[pd.Timestamp]:
    output: List[pd.Timestamp] = []
    for raw in text.replace("，", ",").replace("\n", ",").split(","):
        raw = raw.strip()
        if not raw:
            continue
        try:
            output.append(pd.Timestamp(raw).normalize())
        except Exception:
            pass
    return output


def workday_offset(start_date, offset_days: int, holidays: List[pd.Timestamp]) -> pd.Timestamp:
    if pd.isna(start_date):
        return pd.NaT

    current = pd.Timestamp(start_date).normalize()
    holiday_dates = {h.date() for h in holidays}
    step = 1 if int(offset_days) >= 0 else -1
    remaining = abs(int(offset_days))

    while remaining > 0:
        current += pd.Timedelta(days=step)
        if current.weekday() < 5 and current.date() not in holiday_dates:
            remaining -= 1
    return current


